        "path": "src/Aragami2Trainer/Program.cs",
        "content": "using System;\nusing System.Threading;\n\nnamespace Aragami2Trainer\n{\n    /// <summary>\n    /// Main entry point for the Aragami 2 Trainer application.\n    /// Initializes the trainer and displays a console-based UI.\n    /// </summary>\n    internal class Program\n    {\n        private static bool _running = true;\n        private static TrainerCore _trainer;\n\n        static void Main(string[] args)\n        {\n            Console.Title = \"Aragami 2 Trainer v1.0\";\n            Console.ForegroundColor = ConsoleColor.Cyan;\n            Console.WriteLine(\"========================================\");\n            Console.WriteLine(\"       Aragami 2 Trainer v1.0\");\n            Console.WriteLine(\"========================================\");\n            Console.ResetColor();\n\n            // Initialize trainer core\n            _trainer = new TrainerCore();\n            if (!_trainer.Initialize())\n            {\n                Console.ForegroundColor = ConsoleColor.Red;\n                Console.WriteLine(\"Failed to initialize trainer. Ensure the game is running.\");\n                Console.ResetColor();\n                return;\n            }\n\n            Console.WriteLine(\"Trainer active. Use the following hotkeys:\");\n            Console.WriteLine(\"  [F1] - Toggle Infinite Health\");\n            Console.WriteLine(\"  [F2] - Toggle Infinite Shadow Essence\");\n            Console.WriteLine(\"  [F3] - Toggle One-Hit Kill\");\n            Console.WriteLine(\"  [F4] - Toggle No Detection\");\n            Console.WriteLine(\"  [F5] - Add 1000 XP\");\n            Console.WriteLine(\"  [F6] - Set Skill Points to 99\");\n            Console.WriteLine(\"  [ESC] - Exit Trainer\");\n            Console.WriteLine();\n\n            // Main loop: poll for hotkeys\n            while (_running)\n            {\n                if (Console.KeyAvailable)\n                {\n                    var key = Console.ReadKey(true).Key;\n                    HandleKeyPress(key);\n                }\n\n                // Update trainer state (e.g., memory writes)\n                _trainer.Update();\n                Thread.Sleep(10); // Prevent high CPU usage\n            }\n\n            _trainer.Shutdown();\n            Console.WriteLine(\"Trainer exited. Press any key to close...\");\n            Console.ReadKey();\n        }\n\n        private static void HandleKeyPress(ConsoleKey key)\n        {\n            switch (key)\n            {\n                case ConsoleKey.F1:\n                    _trainer.ToggleInfiniteHealth();\n                    Console.WriteLine($\"Infinite Health: {(_trainer.InfiniteHealthEnabled ? \"ON\" : \"OFF\")}\");\n                    break;\n                case ConsoleKey.F2:\n                    _trainer.ToggleInfiniteShadowEssence();\n                    Console.WriteLine($\"Infinite Shadow Essence: {(_trainer.InfiniteShadowEssenceEnabled ? \"ON\" : \"OFF\")}\");\n                    break;\n                case ConsoleKey.F3:\n                    _trainer.ToggleOneHitKill();\n                    Console.WriteLine($\"One-Hit Kill: {(_trainer.OneHitKillEnabled ? \"ON\" : \"OFF\")}\");\n                    break;\n                case ConsoleKey.F4:\n                    _trainer.ToggleNoDetection();\n                    Console.WriteLine($\"No Detection: {(_trainer.NoDetectionEnabled ? \"ON\" : \"OFF\")}\");\n                    break;\n                case ConsoleKey.F5:\n                    _trainer.AddXp(1000);\n                    Console.WriteLine(\"Added 1000 XP.\");\n                    break;\n                case ConsoleKey.F6:\n                    _trainer.SetSkillPoints(99);\n                    Console.WriteLine(\"Skill Points set to 99.\");\n                    break;\n                case ConsoleKey.Escape:\n                    _running = false;\n                    break;\n            }\n        }\n    }\n}\n"
    },
