        "path": "src/Aragami2Trainer/TrainerCore.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace Aragami2Trainer\n{\n    /// <summary>\n    /// Core class handling memory manipulation for Aragami 2.\n    /// Uses Win32 API calls to read/write process memory.\n    /// </summary>\n    public class TrainerCore\n    {\n        // Win32 API imports\n        [DllImport(\"kernel32.dll\")]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\")]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_ALL_ACCESS = 0x1F0FFF;\n\n        private IntPtr _processHandle;\n        private Process _gameProcess;\n        private IntPtr _baseAddress;\n\n        // Toggle states\n        public bool InfiniteHealthEnabled { get; private set; }\n        public bool InfiniteShadowEssenceEnabled { get; private set; }\n        public bool OneHitKillEnabled { get; private set; }\n        public bool NoDetectionEnabled { get; private set; }\n\n        // Memory offsets (example values, would need to be updated for actual game version)\n        private const long HealthOffset = 0x00A1B2C0;\n        private const long ShadowEssenceOffset = 0x00A1B2C4;\n        private const long DamageMultiplierOffset = 0x00A1B2C8;\n        private const long DetectionOffset = 0x00A1B2CC;\n        private const long XpOffset = 0x00A1B2D0;\n        private const long SkillPointsOffset = 0x00A1B2D4;\n\n        private byte[] _originalHealth;\n        private byte[] _originalShadowEssence;\n        private byte[] _originalDamage;\n        private byte[] _originalDetection;\n\n        /// <summary>\n        /// Initializes the trainer by finding the Aragami 2 process.\n        /// </summary>\n        /// <returns>True if successful, false otherwise.</returns>\n        public bool Initialize()\n        {\n            Process[] processes = Process.GetProcessesByName(\"Aragami2-Win64-Shipping\");\n            if (processes.Length == 0)\n            {\n                processes = Process.GetProcessesByName(\"Aragami2\");\n            }\n\n            if (processes.Length == 0)\n            {\n                Console.WriteLine(\"Aragami 2 process not found.\");\n                return false;\n            }\n\n            _gameProcess = processes[0];\n            _processHandle = OpenProcess(PROCESS_ALL_ACCESS, false, _gameProcess.Id);\n\n            if (_processHandle == IntPtr.Zero)\n            {\n                Console.WriteLine(\"Failed to open process. Try running as administrator.\");\n                return false;\n            }\n\n            // Get base address (usually main module)\n            _baseAddress = _gameProcess.MainModule.BaseAddress;\n            Console.WriteLine($\"Attached to process {_gameProcess.ProcessName} (PID: {_gameProcess.Id})\");\n\n            // Save original values for restoration on shutdown\n            _originalHealth = new byte[4];\n            _originalShadowEssence = new byte[4];\n            _originalDamage = new byte[4];\n            _originalDetection = new byte[4];\n\n            ReadProcessMemory(_processHandle, _baseAddress + HealthOffset, _originalHealth, 4, out _);\n            ReadProcessMemory(_processHandle, _baseAddress + ShadowEssenceOffset, _originalShadowEssence, 4, out _);\n            ReadProcessMemory(_processHandle, _baseAddress + DamageMultiplierOffset, _originalDamage, 4, out _);\n            ReadProcessMemory(_processHandle, _baseAddress + DetectionOffset, _originalDetection, 4, out _);\n\n            return true;\n        }\n\n        /// <summary>\n        /// Toggles infinite health on/off.\n        /// </summary>\n        public void ToggleInfiniteHealth()\n        {\n            InfiniteHealthEnabled = !InfiniteHealthEnabled;\n            if (InfiniteHealthEnabled)\n            {\n                // Write a large health value (e.g., 999999)\n                byte[] value = BitConverter.GetBytes(999999f);\n                WriteProcessMemory(_processHandle, _baseAddress + HealthOffset, value, 4, out _);\n            }\n            else\n            {\n                WriteProcessMemory(_processHandle, _baseAddress + HealthOffset, _originalHealth, 4, out _);\n            }\n        }\n\n        /// <summary>\n        /// Toggles infinite shadow essence on/off.\n        /// </summary>\n        public void ToggleInfiniteShadowEssence()\n        {\n            InfiniteShadowEssenceEnabled = !InfiniteShadowEssenceEnabled;\n            if (InfiniteShadowEssenceEnabled)\n            {\n                byte[] value = BitConverter.GetBytes(9999f);\n                WriteProcessMemory(_processHandle, _baseAddress + ShadowEssenceOffset, value, 4, out _);\n            }\n            else\n            {\n                WriteProcessMemory(_processHandle, _baseAddress + ShadowEssenceOffset, _originalShadowEssence, 4, out _);\n            }\n        }\n\n        /// <summary>\n        /// Toggles one-hit kill on/off.\n        /// </summary>\n        public void ToggleOneHitKill()\n        {\n            OneHitKillEnabled = !OneHitKillEnabled;\n            if (OneHitKillEnabled)\n            {\n                byte[] value = BitConverter.GetBytes(9999f); // High damage multiplier\n                WriteProcessMemory(_processHandle, _baseAddress + DamageMultiplierOffset, value, 4, out _);\n            }\n            else\n            {\n                WriteProcessMemory(_processHandle, _baseAddress + DamageMultiplierOffset, _originalDamage, 4, out _);\n            }\n        }\n\n        /// <summary>\n        /// Toggles no detection on/off.\n        /// </summary>\n        public void ToggleNoDetection()\n        {\n            NoDetectionEnabled = !NoDetectionEnabled;\n            if (NoDetectionEnabled)\n            {\n                byte[] value = BitConverter.GetBytes(0f); // Zero detection\n                WriteProcessMemory(_processHandle, _baseAddress + DetectionOffset, value, 4, out _);\n            }\n            else\n            {\n                WriteProcessMemory(_processHandle, _baseAddress + DetectionOffset, _originalDetection, 4, out _);\n            }\n        }\n\n        /// <summary>\n        /// Adds XP to the player.\n        /// </summary>\n        /// <param name=\"amount\">Amount of XP to add.</param>\n        public void AddXp(int amount)\n        {\n            byte[] buffer = new byte[4];\n            ReadProcessMemory(_processHandle, _baseAddress + XpOffset, buffer, 4, out _);\n            int currentXp = BitConverter.ToInt32(buffer, 0);\n            int newXp = currentXp + amount;\n            byte[] value = BitConverter.GetBytes(newXp);\n            WriteProcessMemory(_processHandle, _baseAddress + XpOffset, value, 4, out _);\n        }\n\n        /// <summary>\n        /// Sets skill points to a specific value.\n        /// </summary>\n        /// <param name=\"points\">Number of skill points to set.</param>\n        public void SetSkillPoints(int points)\n        {\n            byte[] value = BitConverter.GetBytes(points);\n            WriteProcessMemory(_processHandle, _baseAddress + SkillPointsOffset, value, 4, out _);\n        }\n\n        /// <summary>\n        /// Called every frame to maintain cheats (e.g., keep health high).\n        /// </summary>\n        public void Update()\n        {\n            if (InfiniteHealthEnabled)\n            {\n                byte[] value = BitConverter.GetBytes(999999f);\n                WriteProcessMemory(_processHandle, _baseAddress + HealthOffset, value, 4, out _);\n            }\n            if (InfiniteShadowEssenceEnabled)\n            {\n                byte[] value = BitConverter.GetBytes(9999f);\n                WriteProcessMemory(_processHandle, _baseAddress + ShadowEssenceOffset, value, 4, out _);\n            }\n        }\n\n        /// <summary>\n        /// Restores original memory values and cleans up.\n        /// </summary>\n        public void Shutdown()\n        {\n            // Restore original values to avoid game corruption\n            if (_originalHealth != null)\n                WriteProcessMemory(_processHandle, _baseAddress + HealthOffset, _originalHealth, 4, out _);\n            if (_originalShadowEssence != null)\n                WriteProcessMemory(_processHandle, _baseAddress + ShadowEssenceOffset, _originalShadowEssence, 4, out _);\n            if (_originalDamage != null)\n                WriteProcessMemory(_processHandle, _baseAddress + DamageMultiplierOffset, _originalDamage, 4, out _);\n            if (_originalDetection != null)\n                WriteProcessMemory(_processHandle, _baseAddress + DetectionOffset, _originalDetection, 4, out _);\n\n            if (_processHandle != IntPtr.Zero)\n                CloseHandle(_processHandle);\n\n            Console.WriteLine(\"Memory restored. Trainer shut down.\");\n        }\n    }\n}\n"
    },
