        "path": "src/Aragami2Trainer/Config.cs",
        "content": "using System;\nusing System.IO;\nusing System.Text.Json;\n\nnamespace Aragami2Trainer\n{\n    /// <summary>\n    /// Configuration manager for the trainer.\n    /// Loads and saves hotkey bindings and settings from a JSON file.\n    /// </summary>\n    public class Config\n    {\n        private static readonly string ConfigPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, \"trainer_config.json\");\n\n        /// <summary>\n        /// Hotkey for toggling infinite health.\n        /// </summary>\n        public ConsoleKey InfiniteHealthKey { get; set; } = ConsoleKey.F1;\n\n        /// <summary>\n        /// Hotkey for toggling infinite shadow essence.\n        /// </summary>\n        public ConsoleKey InfiniteShadowEssenceKey { get; set; } = ConsoleKey.F2;\n\n        /// <summary>\n        /// Hotkey for toggling one-hit kill.\n        /// </summary>\n        public ConsoleKey OneHitKillKey { get; set; } = ConsoleKey.F3;\n\n        /// <summary>\n        /// Hotkey for toggling no detection.\n        /// </summary>\n        public ConsoleKey NoDetectionKey { get; set; } = ConsoleKey.F4;\n\n        /// <summary>\n        /// Hotkey for adding XP.\n        /// </summary>\n        public ConsoleKey AddXpKey { get; set; } = ConsoleKey.F5;\n\n        /// <summary>\n        /// Hotkey for setting skill points.\n        /// </summary>\n        public ConsoleKey SetSkillPointsKey { get; set; } = ConsoleKey.F6;\n\n        /// <summary>\n        /// Amount of XP to add when the add XP hotkey is pressed.\n        /// </summary>\n        public int XpAmount { get; set; } = 1000;\n\n        /// <summary>\n        /// Number of skill points to set when the skill points hotkey is pressed.\n        /// </summary>\n        public int SkillPointsAmount { get; set; } = 99;\n\n        /// <summary>\n        /// Loads configuration from file, or creates default if not present.\n        /// </summary>\n        /// <returns>Config instance.</returns>\n        public static Config Load()\n        {\n            try\n            {\n                if (File.Exists(ConfigPath))\n                {\n                    string json = File.ReadAllText(ConfigPath);\n                    return JsonSerializer.Deserialize<Config>(json) ?? new Config();\n                }\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to load config: {ex.Message}\");\n            }\n\n            return new Config();\n        }\n\n        /// <summary>\n        /// Saves current configuration to file.\n        /// </summary>\n        public void Save()\n        {\n            try\n            {\n                string json = JsonSerializer.Serialize(this, new JsonSerializerOptions { WriteIndented = true });\n                File.WriteAllText(ConfigPath, json);\n                Console.WriteLine(\"Configuration saved.\");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to save config: {ex.Message}\");\n            }\n        }\n    }\n}\n"
    },
